int nextAvailableTile(int lane) {
    // Bounds checks
    if (tiles == null) return -1;
    if (lane < 0 || lane >= tiles.length) return -1;

    // Iterate from base outward in the specified lane
    Array<Array<Array<Card>>> laneTiles = tiles[lane];
    for (int i = 0; i < laneTiles.length; i++) {
        Array<Card> stackOnTile = laneTiles[i];
        if (stackOnTile == null || stackOnTile.length == 0) {
            return i; // first empty tile closest to the base
        }
    }

    // No available tile found
    return -1;
}
